import React, { useState, useEffect } from 'react';
import './ProfilePage.css';
import { useNavigate } from 'react-router-dom'; // Import useNavigate for redirection

function ProfilePage() {
  const [profile, setProfile] = useState({
    fullName: 'Loading...',
    email: 'Loading...',
    mobileNumber: null,
    username: 'Loading...', // Add username to the state
    // We won't store password here for security reasons, 
    // but we'll display a masked value or indication.
  });
  const [error, setError] = useState(null);
  const navigate = useNavigate(); // Initialize useNavigate for redirection

  useEffect(() => {
    // Set default profile initially
    const defaultProfile = {
      fullName: 'Guest User',
      email: 'guest@example.com',
      mobileNumber: null,
      username: 'guest', // Default username
    };

    setProfile(defaultProfile);

    // Fetch profile data from API
    fetch('/api/profile')
      .then(response => {
        if (!response.ok) {
          throw new Error(`Failed to fetch profile: ${response.status}`);
        }
        return response.json();
      })
      .then(data => {
        setProfile(data);
      })
      .catch(err => {
        console.error('Error fetching profile:', err);
        setError('Failed to load profile information.');
      });
  }, []);

  const handleEditProfileClick = () => {
    navigate('/edit-profile'); // Redirect to the edit profile page
  };

  const handleAddMobile = () => {
    alert('Add mobile number functionality will be implemented here.');
  };

  return (
    <div className="main-content">
      <div className="profile-container">
        <div className="profile-card">
          <div style={{ textAlign: 'right', marginBottom: '15px' }}>
            <button id="editProfileButton" className="edit-button" onClick={handleEditProfileClick}>
              Edit Profile
            </button>
          </div>
          <h2>Login & Security</h2>
          <div className="profile-info">
            <div className="info-item">
              <span className="label">Name</span>
              <span id="profile-full-name">{profile.fullName || 'N/A'}</span>
            </div>
            <div className="info-item">
              <span className="label">Email</span>
              <span id="profile-email">{profile.email || 'N/A'}</span>
            </div>
            <div className="info-item">
              <span className="label">Primary mobile number</span>
              {profile.mobileNumber ? (
                <div className="mobile-info">
                  <span id="profile-mobile">{profile.mobileNumber}</span>
                  <p className="security-note">
                    <span style={{ color: 'orange', fontSize: '1.2em' }}>⚠️</span>
                    For stronger account security, add your mobile number. If there's an
                    unusual sign-in, we'll text you and verify that it's really you.
                  </p>
                </div>
              ) : (
                <button className="add-button" onClick={handleAddMobile}>Add</button>
              )}
            </div>
            <div className="info-item">
              <span className="label">Username</span>
              <span id="profile-username">{profile.username || 'N/A'}</span>
            </div>
            <div className="info-item">
              <span className="label">Password</span>
              <span id="profile-password">********</span> {/* Display masked password */}
            </div>
          </div>
          {error && <p className="error-message">{error}</p>}
        </div>
      </div>
    </div>
  );
}

export default ProfilePage;
